5: ### Express.js - Minimalist Framework
6: 
7: **Basic Setup:**
8: 
9: ```typescript
10: import express, { Request, Response, NextFunction } from "express";
11: import helmet from "helmet";
12: import cors from "cors";
13: import compression from "compression";
14: 
15: const app = express();
16: 
17: // Security middleware
18: app.use(helmet());
19: app.use(cors({ origin: process.env.ALLOWED_ORIGINS?.split(",") }));
20: app.use(compression());
21: 
22: // Body parsing
23: app.use(express.json({ limit: "10mb" }));
24: app.use(express.urlencoded({ extended: true, limit: "10mb" }));
25: 
26: // Request logging
27: app.use((req: Request, res: Response, next: NextFunction) => {
28:   console.log(`${req.method} ${req.path}`);
29:   next();
30: });
31: 
32: const PORT = process.env.PORT || 3000;
33: app.listen(PORT, () => {
34:   console.log(`Server running on port ${PORT}`);
35: });
