90: ## Architectural Patterns
91: 
92: ### Pattern 1: Layered Architecture
93: 
94: **Structure:**
95: 
96: ```
97: src/
98: ├── controllers/     # Handle HTTP requests/responses
99: ├── services/        # Business logic
100: ├── repositories/    # Data access layer
101: ├── models/          # Data models
102: ├── middleware/      # Express/Fastify middleware
103: ├── routes/          # Route definitions
104: ├── utils/           # Helper functions
105: ├── config/          # Configuration
106: └── types/           # TypeScript types
107: ```
108: 
109: **Controller Layer:**
110: 
111: ```typescript
112: // controllers/user.controller.ts
113: import { Request, Response, NextFunction } from "express";
114: import { UserService } from "../services/user.service";
115: import { CreateUserDTO, UpdateUserDTO } from "../types/user.types";
116: 
117: export class UserController {
118:   constructor(private userService: UserService) {}
119: 
120:   async createUser(req: Request, res: Response, next: NextFunction) {
121:     try {
122:       const userData: CreateUserDTO = req.body;
123:       const user = await this.userService.createUser(userData);
124:       res.status(201).json(user);
125:     } catch (error) {
126:       next(error);
127:     }
128:   }
129: 
130:   async getUser(req: Request, res: Response, next: NextFunction) {
131:     try {
132:       const { id } = req.params;
133:       const user = await this.userService.getUserById(id);
134:       res.json(user);
135:     } catch (error) {
136:       next(error);
137:     }
138:   }
139: 
140:   async updateUser(req: Request, res: Response, next: NextFunction) {
141:     try {
142:       const { id } = req.params;
143:       const updates: UpdateUserDTO = req.body;
144:       const user = await this.userService.updateUser(id, updates);
145:       res.json(user);
146:     } catch (error) {
147:       next(error);
148:     }
149:   }
150: 
151:   async deleteUser(req: Request, res: Response, next: NextFunction) {
152:     try {
153:       const { id } = req.params;
154:       await this.userService.deleteUser(id);
155:       res.status(204).send();
156:     } catch (error) {
