163: **Service Layer:**
164: 
165: ```typescript
166: // services/user.service.ts
167: import { UserRepository } from "../repositories/user.repository";
168: import { CreateUserDTO, UpdateUserDTO, User } from "../types/user.types";
169: import { NotFoundError, ValidationError } from "../utils/errors";
170: import bcrypt from "bcrypt";
171: 
172: export class UserService {
173:   constructor(private userRepository: UserRepository) {}
174: 
175:   async createUser(userData: CreateUserDTO): Promise<User> {
176:     // Validation
177:     const existingUser = await this.userRepository.findByEmail(userData.email);
178:     if (existingUser) {
179:       throw new ValidationError("Email already exists");
180:     }
181: 
182:     // Hash password
183:     const hashedPassword = await bcrypt.hash(userData.password, 10);
184: 
185:     // Create user
186:     const user = await this.userRepository.create({
187:       ...userData,
188:       password: hashedPassword,
189:     });
190: 
191:     // Remove password from response
192:     const { password, ...userWithoutPassword } = user;
193:     return userWithoutPassword as User;
194:   }
195: 
196:   async getUserById(id: string): Promise<User> {
197:     const user = await this.userRepository.findById(id);
198:     if (!user) {
199:       throw new NotFoundError("User not found");
200:     }
201:     const { password, ...userWithoutPassword } = user;
202:     return userWithoutPassword as User;
203:   }
204: 
205:   async updateUser(id: string, updates: UpdateUserDTO): Promise<User> {
206:     const user = await this.userRepository.update(id, updates);
207:     if (!user) {
208:       throw new NotFoundError("User not found");
209:     }
210:     const { password, ...userWithoutPassword } = user;
211:     return userWithoutPassword as User;
212:   }
213: 
214:   async deleteUser(id: string): Promise<void> {
215:     const deleted = await this.userRepository.delete(id);
216:     if (!deleted) {
217:       throw new NotFoundError("User not found");
218:     }
219:   }
220: }
