223: **Repository Layer:**
224: 
225: ```typescript
226: // repositories/user.repository.ts
227: import { Pool } from "pg";
228: import { CreateUserDTO, UpdateUserDTO, UserEntity } from "../types/user.types";
229: 
230: export class UserRepository {
231:   constructor(private db: Pool) {}
232: 
233:   async create(
234:     userData: CreateUserDTO & { password: string },
235:   ): Promise<UserEntity> {
236:     const query = `
237:       INSERT INTO users (name, email, password)
238:       VALUES ($1, $2, $3)
239:       RETURNING id, name, email, password, created_at, updated_at
240:     `;
241:     const { rows } = await this.db.query(query, [
242:       userData.name,
243:       userData.email,
244:       userData.password,
245:     ]);
246:     return rows[0];
247:   }
248: 
249:   async findById(id: string): Promise<UserEntity | null> {
250:     const query = "SELECT * FROM users WHERE id = $1";
251:     const { rows } = await this.db.query(query, [id]);
252:     return rows[0] || null;
253:   }
254: 
255:   async findByEmail(email: string): Promise<UserEntity | null> {
256:     const query = "SELECT * FROM users WHERE email = $1";
257:     const { rows } = await this.db.query(query, [email]);
258:     return rows[0] || null;
259:   }
260: 
261:   async update(id: string, updates: UpdateUserDTO): Promise<UserEntity | null> {
262:     const fields = Object.keys(updates);
263:     const values = Object.values(updates);
264: 
265:     const setClause = fields
266:       .map((field, idx) => `${field} = $${idx + 2}`)
267:       .join(", ");
268: 
269:     const query = `
270:       UPDATE users
271:       SET ${setClause}, updated_at = CURRENT_TIMESTAMP
272:       WHERE id = $1
273:       RETURNING *
274:     `;
275: 
276:     const { rows } = await this.db.query(query, [id, ...values]);
277:     return rows[0] || null;
278:   }
279: 
280:   async delete(id: string): Promise<boolean> {
281:     const query = "DELETE FROM users WHERE id = $1";
282:     const { rowCount } = await this.db.query(query, [id]);
283:     return rowCount > 0;
284:   }
285: }
