292: ## Middleware Patterns
293: 
294: ### Authentication Middleware
295: 
296: ```typescript
297: // middleware/auth.middleware.ts
298: import { Request, Response, NextFunction } from "express";
299: import jwt from "jsonwebtoken";
300: import { UnauthorizedError } from "../utils/errors";
301: 
302: interface JWTPayload {
303:   userId: string;
304:   email: string;
305: }
306: 
307: declare global {
308:   namespace Express {
309:     interface Request {
310:       user?: JWTPayload;
311:     }
312:   }
313: }
314: 
315: export const authenticate = async (
316:   req: Request,
317:   res: Response,
318:   next: NextFunction,
319: ) => {
320:   try {
321:     const token = req.headers.authorization?.replace("Bearer ", "");
322: 
323:     if (!token) {
324:       throw new UnauthorizedError("No token provided");
325:     }
326: 
327:     const payload = jwt.verify(token, process.env.JWT_SECRET!) as JWTPayload;
328: 
329:     req.user = payload;
330:     next();
331:   } catch (error) {
332:     next(new UnauthorizedError("Invalid token"));
333:   }
334: };
335: 
336: export const authorize = (...roles: string[]) => {
337:   return async (req: Request, res: Response, next: NextFunction) => {
338:     if (!req.user) {
339:       return next(new UnauthorizedError("Not authenticated"));
340:     }
341: 
342:     // Check if user has required role
343:     const hasRole = roles.some((role) => req.user?.roles?.includes(role));
344: 
345:     if (!hasRole) {
346:       return next(new UnauthorizedError("Insufficient permissions"));
347:     }
348: 
349:     next();
350:   };
351: };
352: ```
