354: ### Validation Middleware
355: 
356: ```typescript
357: // middleware/validation.middleware.ts
358: import { Request, Response, NextFunction } from "express";
359: import { AnyZodObject, ZodError } from "zod";
360: import { ValidationError } from "../utils/errors";
361: 
362: export const validate = (schema: AnyZodObject) => {
363:   return async (req: Request, res: Response, next: NextFunction) => {
364:     try {
365:       await schema.parseAsync({
366:         body: req.body,
367:         query: req.query,
368:         params: req.params,
369:       });
370:       next();
371:     } catch (error) {
372:       if (error instanceof ZodError) {
373:         const errors = error.errors.map((err) => ({
374:           field: err.path.join("."),
375:           message: err.message,
376:         }));
377:         next(new ValidationError("Validation failed", errors));
378:       } else {
379:         next(error);
380:       }
381:     }
382:   };
383: };
384: 
385: // Usage with Zod
386: import { z } from "zod";
387: 
388: const createUserSchema = z.object({
389:   body: z.object({
390:     name: z.string().min(1),
391:     email: z.string().email(),
392:     password: z.string().min(8),
393:   }),
394: });
395: 
396: router.post("/users", validate(createUserSchema), userController.createUser);
397: ```
