435: ### Request Logging Middleware
436: 
437: ```typescript
438: // middleware/logger.middleware.ts
439: import { Request, Response, NextFunction } from "express";
440: import pino from "pino";
441: 
442: const logger = pino({
443:   level: process.env.LOG_LEVEL || "info",
444:   transport: {
445:     target: "pino-pretty",
446:     options: { colorize: true },
447:   },
448: });
449: 
450: export const requestLogger = (
451:   req: Request,
452:   res: Response,
453:   next: NextFunction,
454: ) => {
455:   const start = Date.now();
456: 
457:   // Log response when finished
458:   res.on("finish", () => {
459:     const duration = Date.now() - start;
460:     logger.info({
461:       method: req.method,
462:       url: req.url,
463:       status: res.statusCode,
464:       duration: `${duration}ms`,
465:       userAgent: req.headers["user-agent"],
466:       ip: req.ip,
467:     });
468:   });
469: 
470:   next();
471: };
472: 
473: export { logger };
474: ```
