476: ## Error Handling
477: 
478: ### Custom Error Classes
479: 
480: ```typescript
481: // utils/errors.ts
482: export class AppError extends Error {
483:   constructor(
484:     public message: string,
485:     public statusCode: number = 500,
486:     public isOperational: boolean = true,
487:   ) {
488:     super(message);
489:     Object.setPrototypeOf(this, AppError.prototype);
490:     Error.captureStackTrace(this, this.constructor);
491:   }
492: }
493: 
494: export class ValidationError extends AppError {
495:   constructor(
496:     message: string,
497:     public errors?: any[],
498:   ) {
499:     super(message, 400);
500:   }
501: }
502: 
503: export class NotFoundError extends AppError {
504:   constructor(message: string = "Resource not found") {
505:     super(message, 404);
506:   }
507: }
508: 
509: export class UnauthorizedError extends AppError {
510:   constructor(message: string = "Unauthorized") {
511:     super(message, 401);
512:   }
513: }
514: 
515: export class ForbiddenError extends AppError {
516:   constructor(message: string = "Forbidden") {
517:     super(message, 403);
518:   }
519: }
520: 
521: export class ConflictError extends AppError {
522:   constructor(message: string) {
523:     super(message, 409);
524:   }
525: }
526: ```
