528: ### Global Error Handler
529: 
530: ```typescript
531: // middleware/error-handler.ts
532: import { Request, Response, NextFunction } from "express";
533: import { AppError } from "../utils/errors";
534: import { logger } from "./logger.middleware";
535: 
536: export const errorHandler = (
537:   err: Error,
538:   req: Request,
539:   res: Response,
540:   next: NextFunction,
541: ) => {
542:   if (err instanceof AppError) {
543:     return res.status(err.statusCode).json({
544:       status: "error",
545:       message: err.message,
546:       ...(err instanceof ValidationError && { errors: err.errors }),
547:     });
548:   }
549: 
550:   // Log unexpected errors
551:   logger.error({
552:     error: err.message,
553:     stack: err.stack,
554:     url: req.url,
555:     method: req.method,
556:   });
557: 
558:   // Don't leak error details in production
559:   const message =
560:     process.env.NODE_ENV === "production"
561:       ? "Internal server error"
562:       : err.message;
563: 
564:   res.status(500).json({
565:     status: "error",
566:     message,
567:   });
568: };
569: 
570: // Async error wrapper
571: export const asyncHandler = (
572:   fn: (req: Request, res: Response, next: NextFunction) => Promise<any>,
573: ) => {
574:   return (req: Request, res: Response, next: NextFunction) => {
575:     Promise.resolve(fn(req, res, next)).catch(next);
576:   };
577: };
578: ```
