export interface Element {
  id: number;
  name: string;
  alias: string;
  description: string;
  category: string;
}

import fs from 'fs/promises';
import path from 'path';
import { Element } from '../types/element.types';

export class ElementService {
  private jsonPath: string;

  constructor() {
    // Resolve relative to this file's compiled location (dist/services/)
    // or fallback to source location
    this.jsonPath = path.join(__dirname, '../data/elements.json');
  }

  async getAllElements(): Promise<Element[]> {
    try {
      try {
        const data = await fs.readFile(this.jsonPath, 'utf-8');
        return JSON.parse(data);
      } catch (err) {
        // Fallback to absolute workspace path in dev environment
        const fallbackPath = path.join(process.cwd(), 'src/data/elements.json');
        const data = await fs.readFile(fallbackPath, 'utf-8');
        return JSON.parse(data);
      }
    } catch (error) {
      console.error('Error reading elements.json:', error);
      throw new Error('Could not read elements data');
    }
  }
}

import { Request, Response, NextFunction } from 'express';
import { ElementService } from '../services/element.service';

export class ElementController {
  private elementService: ElementService;

  constructor() {
    this.elementService = new ElementService();
  }

  getElements = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const elements = await this.elementService.getAllElements();

      // Ensure only (id, name, alias, description, category) are returned, as requested
      const sanitizedElements = elements.map(el => ({
        id: el.id,
        name: el.name,
        alias: el.alias,
        description: el.description,
        category: el.category
      }));

      res.status(200).json(sanitizedElements);
    } catch (error) {
      next(error);
    }
  };
}

import { Router } from 'express';
import { ElementController } from '../controllers/element.controller';

const router = Router();
const elementController = new ElementController();

router.get('/elements', elementController.getElements);

export default router;

import { Request, Response, NextFunction } from 'express';

export class AppError extends Error {
  constructor(
    public message: string,
    public statusCode: number = 500
  ) {
    super(message);
    Object.setPrototypeOf(this, AppError.prototype);
  }
}

export const notFoundHandler = (req: Request, res: Response, next: NextFunction) => {
  res.status(404).json({
    status: 'error',
    message: `Route not found: ${req.method} ${req.originalUrl}`
  });
};

export const errorHandler = (
  err: Error,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  const statusCode = err instanceof AppError ? err.statusCode : 500;
  const message = err.message || 'Internal server error';

  console.error(`[Error] ${statusCode} - ${message}`, err.stack);

  res.status(statusCode).json({
    status: 'error',
    message
  });
};

